+/// Check if the complement of cases within a value range forms a contiguous
+/// range (possibly wrapping). Returns true if the complement is contiguous,
+/// and sets ComplementMin and ComplementSize accordingly.
+///
+/// For example, with value range [0, 6) and cases {0, 4, 5}:
+/// - Complement is {1, 2, 3} = [1, 4)
+/// - ComplementMin = 1, ComplementSize = 3
+/// - This can be tested as: (val - 1) ult 3
+static bool getComplementRangeInfo(ArrayRef<ConstantInt *> Cases,
+                                   const ConstantRange &Range,
+                                   APInt &ComplementMin,
+                                   uint64_t &ComplementSize) {
+  if (Cases.empty())
+    return false;
+
+  uint32_t BitWidth = Cases[0]->getBitWidth();
+  APInt RangeMin = Range.getLower();
+  APInt RangeUpper = Range.getUpper();
+
+  // Compute the size of the range
+  uint64_t RangeSize;
+  if (Range.isFullSet()) {
+    // Full set - size is 2^BitWidth
+    if (BitWidth >= 64)
+      return false; // Too large to handle
+    RangeSize = 1ULL << BitWidth;
+  } else {
+    APInt Size = RangeUpper - RangeMin;
+    if (Size.getLimitedValue(UINT64_MAX + 1ULL) > UINT64_MAX)
+      return false;
+    RangeSize = Size.getLimitedValue();
+  }
+
+  if (RangeSize == 0)
+    return false;
+
+  uint64_t NumCases = Cases.size();
+  if (NumCases >= RangeSize)
+    return false; // No complement or complement is empty
+
+  ComplementSize = RangeSize - NumCases;
+
+  // Sort cases
+  SmallVector<ConstantInt *, 8> SortedCases(Cases.begin(), Cases.end());
+  array_pod_sort(SortedCases.begin(), SortedCases.end(), constantIntSortPredicate);
+
+  // Find the largest gap between consecutive cases (including wraparound)
+  // The complement is contiguous iff there's exactly one gap of size ComplementSize
+  APInt MaxGapStart = SortedCases.back()->getValue();
+  APInt MaxGapSize = APInt::getZero(BitWidth);
+
+  for (size_t I = 0, E = SortedCases.size(); I < E; ++I) {
+    APInt CurVal = SortedCases[I]->getValue();
+    APInt PrevVal = SortedCases[I == 0 ? E - 1 : I - 1]->getValue();
+
+    // Gap from PrevVal to CurVal (with wrapping)
+    APInt GapSize;
+    if (CurVal.ugt(PrevVal)) {
+      GapSize = CurVal - PrevVal - 1;
+    } else {
+      // Wraparound: gap goes from PrevVal to end of range, then from start to CurVal
+      GapSize = RangeUpper - PrevVal - 1 + CurVal - RangeMin;
+    }
+    if (GapSize.ugt(MaxGapSize)) {
+      MaxGapSize = GapSize;
+      MaxGapStart = PrevVal;
+    }
+  }
+
+  // Check if the largest gap equals the complement size
+  if (MaxGapSize.getLimitedValue() != ComplementSize)
+    return false;
+
+  // Complement starts at MaxGapStart + 1
+  ComplementMin = MaxGapStart + 1;
+  return true;
+}
