  // Figure out if one of the sets of cases form a contiguous range.
  SmallVectorImpl<ConstantInt *> *ContiguousCases = nullptr;
  BasicBlock *ContiguousDest = nullptr;
  BasicBlock *OtherDest = nullptr;
  bool ComplementRange = false;
  APInt ComplementMinVal;
  uint64_t ComplementSize = 0;

  // Try normal contiguity first
  if (!CasesA.empty() && casesAreContiguous(CasesA)) {
    ContiguousCases = &CasesA;
    ContiguousDest = DestA;
    OtherDest = DestB;
  } else if (casesAreContiguous(CasesB)) {
    ContiguousCases = &CasesB;
    ContiguousDest = DestB;
    OtherDest = DestA;
  } else {
    // Try complement contiguity with wrapping
    // Get the value range from the switch condition if it's an argument
    std::optional<ConstantRange> ValueRange;
    if (auto *Cond = dyn_cast<Argument>(SI->getCondition()))
      ValueRange = Cond->getRange();

    if (ValueRange && !ValueRange->isEmptySet()) {
      // Check if complement of CasesA is contiguous
      if (!CasesA.empty() &&
          getComplementRangeInfo(CasesA, *ValueRange, ComplementMinVal, ComplementSize)) {
        ContiguousCases = &CasesA;
        ContiguousDest = DestA;
        OtherDest = DestB;
        ComplementRange = true;
      } else if (getComplementRangeInfo(CasesB, *ValueRange, ComplementMinVal, ComplementSize)) {
        ContiguousCases = &CasesB;
        ContiguousDest = DestB;
        OtherDest = DestA;
        ComplementRange = true;
      }
    }

    if (!ComplementRange)
      return false;
  }
